import{_ as a,o,c as r,a3 as t}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"197. Accrued Days Off","description":"","frontmatter":{"title":"197. Accrued Days Off","eba":"Mental Health Services 2024-2028","topics":["leave","annual-leave","wages"]},"headers":[],"relativePath":"ebas/mental-health/management-admin/hours-of-work/197-accrued-days-off.md","filePath":"ebas/mental-health/management-admin/hours-of-work/197-accrued-days-off.md"}'),n={name:"ebas/mental-health/management-admin/hours-of-work/197-accrued-days-off.md"};function s(c,e,d,l,i,f){return o(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="_197-accrued-days-off" tabindex="-1">197. Accrued Days Off <a class="header-anchor" href="#_197-accrued-days-off" aria-label="Permalink to &quot;197. Accrued Days Off&quot;">​</a></h1><p><strong>197.1</strong> Where the system of working provides for accrued days off, Employees shall work an additional 0.4 hours per day, or 2 hours per week, to facilitate one accrued day off (ADO) after every 4 weeks of service.</p><p><strong>197.2</strong> The maximum ADOs shall be 13 in any calendar year, provided that one (1) ADO shall be taken in conjunction with a period of annual leave, for which no additional payment is to be made.</p><p><strong>197.3</strong> Taking of ADOS Wherever practicable, an ADO will be on the date requested by the Employee.</p><p><strong>197.4</strong> Public holidays and Accrued Days Off Where an Employee&#39;s accrued day of falls on a public holiday, another day shall be determined by Employer to be taken in lieu thereof, within the same 4-week cycle (where practicable).</p>',5)])])}const u=a(n,[["render",s]]);export{m as __pageData,u as default};
